import type { CSSObject } from '@ant-design/cssinjs';

import type { GenerateStyle } from '../../theme/internal';
import type { ButtonToken } from './token';

const genButtonBorderStyle = (buttonTypeCls: string, borderColor: string) => ({
  // Border
  [`> span, > ${buttonTypeCls}`]: {
    '&:not(:last-child)': {
      [`&, & > ${buttonTypeCls}`]: {
        '&:not(:disabled)': {
          borderInlineEndColor: borderColor,
        },
      },
    },

    '&:not(:first-child)': {
      [`&, & > ${buttonTypeCls}`]: {
        '&:not(:disabled)': {
          borderInlineStartColor: borderColor,
        },
      },
    },
  },
});

const genGroupStyle: GenerateStyle<ButtonToken, CSSObject> = (token) => {
  const { componentCls, fontSize, lineWidth, groupBorderColor, colorErrorHover } = token;

  return {
    [`${componentCls}-group`]: [
      {
        position: 'relative',
        display: 'inline-flex',

        // Border
        [`> span, > ${componentCls}`]: {
          '&:not(:last-child)': {
            [`&, & > ${componentCls}`]: {
              borderStartEndRadius: 0,
              borderEndEndRadius: 0,
            },
          },

          '&:not(:first-child)': {
            marginInlineStart: token.calc(lineWidth).mul(-1).equal(),

            [`&, & > ${componentCls}`]: {
              borderStartStartRadius: 0,
              borderEndStartRadius: 0,
            },
          },
        },

        [componentCls]: {
          position: 'relative',
          zIndex: 1,

          '&:hover, &:focus, &:active': {
            zIndex: 2,
          },

          '&[disabled]': {
            zIndex: 0,
          },
        },

        [`${componentCls}-icon-only`]: {
          fontSize,
        },
      },

      // Border Color
      genButtonBorderStyle(`${componentCls}-primary`, groupBorderColor),
      genButtonBorderStyle(`${componentCls}-danger`, colorErrorHover),
    ],
  };
};

export default genGroupStyle;

import type { CSSObject } from '@ant-design/cssinjs';

import type { DrawerToken } from '.';
import type { GenerateStyle } from '../../theme/internal';

type Direction = 'left' | 'right' | 'top' | 'bottom';

const getMoveTranslate = (direction: Direction) => {
  const value = '100%';
  return {
    left: `translateX(-${value})`,
    right: `translateX(${value})`,
    top: `translateY(-${value})`,
    bottom: `translateY(${value})`,
  }[direction];
};

const getEnterLeaveStyle = (startStyle: React.CSSProperties, endStyle: React.CSSProperties) => ({
  '&-enter, &-appear': {
    ...startStyle,
    '&-active': endStyle,
  },
  '&-leave': {
    ...endStyle,
    '&-active': startStyle,
  },
});

const getFadeStyle = (from: number, duration: string) => ({
  '&-enter, &-appear, &-leave': {
    '&-start': {
      transition: 'none',
    },
    '&-active': {
      transition: `all ${duration}`,
    },
  },
  ...getEnterLeaveStyle(
    {
      opacity: from,
    },
    {
      opacity: 1,
    },
  ),
});

const getPanelMotionStyles = (direction: Direction, duration: string) => [
  getFadeStyle(0.7, duration),
  getEnterLeaveStyle(
    {
      transform: getMoveTranslate(direction),
    },
    {
      transform: 'none',
    },
  ),
];

const genMotionStyle: GenerateStyle<DrawerToken, CSSObject> = (token) => {
  const { componentCls, motionDurationSlow } = token;
  return {
    [componentCls]: {
      // ======================== Mask ========================
      [`${componentCls}-mask-motion`]: getFadeStyle(0, motionDurationSlow),
      // ======================= Panel ========================
      [`${componentCls}-panel-motion`]: ['left', 'right', 'top', 'bottom'].reduce(
        (obj, direction) => {
          return {
            ...obj,
            [`&-${direction}`]: getPanelMotionStyles(direction as Direction, motionDurationSlow),
          };
        },
        {},
      ),
    },
  };
};

export default genMotionStyle;

import type { Agent } from 'package-manager-detector'
import fs from 'node:fs'
import path from 'node:path'
import process from 'node:process'
import ini from 'ini'
import { detect } from './detect'

const customRcPath = process.env.NI_CONFIG_FILE

const home = process.platform === 'win32'
  ? process.env.USERPROFILE
  : process.env.HOME

const defaultRcPath = path.join(home || '~/', '.nirc')

const rcPath = customRcPath || defaultRcPath

interface Config {
  defaultAgent: Agent | 'prompt'
  globalAgent: Agent
  runAgent: 'node' | undefined
  useSfw: boolean
  catalog: boolean
  noLastCommand: boolean
}

const defaultConfig: Config = {
  defaultAgent: 'prompt',
  globalAgent: 'npm',
  runAgent: undefined,
  useSfw: false,
  catalog: true,
  noLastCommand: false,
}

let config: Config | undefined

export async function getConfig(): Promise<Config> {
  if (!config) {
    config = { ...defaultConfig, ...fs.existsSync(rcPath)
      ? ini.parse(fs.readFileSync(rcPath, 'utf-8'))
      : null }

    if (process.env.NI_DEFAULT_AGENT)
      config.defaultAgent = process.env.NI_DEFAULT_AGENT as Agent

    if (process.env.NI_GLOBAL_AGENT)
      config.globalAgent = process.env.NI_GLOBAL_AGENT as Agent

    if (process.env.NI_RUN_AGENT === 'node')
      config.runAgent = process.env.NI_RUN_AGENT

    if (process.env.NI_USE_SFW !== undefined)
      config.useSfw = process.env.NI_USE_SFW === 'true'

    if (process.env.NI_CATALOG !== undefined)
      config.catalog = process.env.NI_CATALOG !== 'false'

    if (process.env.NI_NO_LAST_COMMAND !== undefined)
      config.noLastCommand = process.env.NI_NO_LAST_COMMAND === 'true'

    const agent = await detect({ programmatic: true })
    if (agent)
      config.defaultAgent = agent
  }

  return config
}

export async function getDefaultAgent(programmatic?: boolean) {
  const { defaultAgent } = await getConfig()
  if (defaultAgent === 'prompt' && (programmatic || process.env.CI))
    return 'npm'
  return defaultAgent
}

export async function getGlobalAgent() {
  const { globalAgent } = await getConfig()
  return globalAgent
}

export async function getRunAgent() {
  const { runAgent } = await getConfig()
  return runAgent
}

export async function getUseSfw() {
  const { useSfw } = await getConfig()
  return useSfw
}

export async function getCatalog() {
  const { catalog } = await getConfig()
  return catalog
}

import type { PnpmWorkspaceYaml } from 'pnpm-workspace-yaml'
import type { CommonOptions, RawDep, YarnWorkspaceMeta } from '../types'
import { readFile, writeFile } from 'node:fs/promises'
import { resolve } from 'pathe'
import { parsePnpmWorkspaceYaml } from 'pnpm-workspace-yaml'
import { dumpDependencies, parseDependency } from './dependencies'

export async function loadYarnWorkspace(
  relative: string,
  options: CommonOptions,
  shouldUpdate: (name: string) => boolean,
): Promise<YarnWorkspaceMeta[]> {
  const filepath = resolve(options.cwd ?? '', relative)
  const rawText = await readFile(filepath, 'utf-8')
  const context = parsePnpmWorkspaceYaml(rawText)
  const raw = context.getDocument().toJSON()

  const catalogs: YarnWorkspaceMeta[] = []

  function createYarnWorkspaceEntry(name: string, map: Record<string, string>): YarnWorkspaceMeta {
    const deps: RawDep[] = Object.entries(map)
      .map(([pkg, version]) => parseDependency({ name: pkg, version, type: 'yarn-workspace', shouldUpdate }))

    return {
      name,
      private: true,
      version: '',
      type: '.yarnrc.yml',
      relative,
      filepath,
      raw,
      context,
      deps,
      resolved: [],
    } satisfies YarnWorkspaceMeta
  }

  if (raw?.catalog) {
    catalogs.push(
      createYarnWorkspaceEntry('yarn-catalog:default', raw.catalog),
    )
  }

  if (raw?.catalogs) {
    for (const key of Object.keys(raw.catalogs)) {
      catalogs.push(
        createYarnWorkspaceEntry(`yarn-catalog:${key}`, raw.catalogs[key]),
      )
    }
  }

  return catalogs
}

export async function writeYarnWorkspace(
  pkg: YarnWorkspaceMeta,
  _options: CommonOptions,
) {
  const versions = dumpDependencies(pkg.resolved, 'yarn-workspace')

  if (!Object.keys(versions).length)
    return

  if (pkg.name.startsWith('yarn-catalog:')) {
    const catalogName = pkg.name.replace('yarn-catalog:', '')
    for (const [key, targetVersion] of Object.entries(versions)) {
      pkg.context.setPackage(catalogName, key, targetVersion)
    }
  }
  else {
    const paths = pkg.name.replace('yarn-workspace:', '').split(/\./g)
    for (const [key, targetVersion] of Object.entries(versions)) {
      pkg.context.setPath([...paths, key], targetVersion)
    }
  }

  if (pkg.context.hasChanged()) {
    await writeYaml(pkg, pkg.context)
  }
}

export function writeYaml(pkg: YarnWorkspaceMeta, document: PnpmWorkspaceYaml) {
  return writeFile(pkg.filepath, document.toString(), 'utf8')
}

