import { PackageGroup, VersionType } from "@changesets/types";
import { Package } from "@manypkg/get-packages";
import semverGt from "semver/functions/gt";
import { InternalRelease } from "./types";
import { InternalError } from "@changesets/errors";

export function getHighestReleaseType(
  releases: InternalRelease[]
): VersionType {
  if (releases.length === 0) {
    throw new Error(
      `Large internal Changesets error when calculating highest release type in the set of releases. Please contact the maintainers`
    );
  }

  let highestReleaseType: VersionType = "none";

  for (let release of releases) {
    switch (release.type) {
      case "major":
        return "major";
      case "minor":
        highestReleaseType = "minor";
        break;
      case "patch":
        if (highestReleaseType === "none") {
          highestReleaseType = "patch";
        }
        break;
    }
  }

  return highestReleaseType;
}

export function getCurrentHighestVersion(
  packageGroup: PackageGroup,
  packagesByName: Map<string, Package>
): string {
  let highestVersion: string | undefined;

  for (let pkgName of packageGroup) {
    let pkg = mapGetOrThrowInternal(
      packagesByName,
      pkgName,
      `We were unable to version for package group: ${pkgName} in package group: ${packageGroup.toString()}`
    );

    if (
      highestVersion === undefined ||
      semverGt(pkg.packageJson.version, highestVersion)
    ) {
      highestVersion = pkg.packageJson.version;
    }
  }

  return highestVersion!;
}

export function mapGetOrThrow<V extends {}>(
  map: Map<string, V>,
  key: string,
  errorMessage: string
): V {
  const value = map.get(key);
  if (value === undefined) {
    throw new Error(errorMessage);
  }
  return value;
}

export function mapGetOrThrowInternal<V extends {}>(
  map: Map<string, V>,
  key: string,
  errorMessage: string
): V {
  const value = map.get(key);
  if (value === undefined) {
    throw new InternalError(errorMessage);
  }
  return value;
}

import util from 'node:util'
import { isMainThread, parentPort } from 'node:worker_threads'
import colors from 'picocolors'

type LOG_TYPE = 'info' | 'success' | 'error' | 'warn'

export const colorize = (type: LOG_TYPE, data: any, onlyImportant = false) => {
  if (onlyImportant && (type === 'info' || type === 'success')) return data

  const color =
    type === 'info'
      ? 'blue'
      : type === 'error'
        ? 'red'
        : type === 'warn'
          ? 'yellow'
          : 'green'
  return colors[color](data)
}

export const makeLabel = (
  name: string | undefined,
  input: string,
  type: LOG_TYPE,
) => {
  return [
    name && `${colors.dim('[')}${name.toUpperCase()}${colors.dim(']')}`,
    colorize(type, input.toUpperCase()),
  ]
    .filter(Boolean)
    .join(' ')
}

let silent = false

export function setSilent(isSilent?: boolean) {
  silent = !!isSilent
}

export function getSilent() {
  return silent
}

export type Logger = ReturnType<typeof createLogger>

export const createLogger = (name?: string) => {
  return {
    setName(_name: string) {
      name = _name
    },

    success(label: string, ...args: any[]) {
      return this.log(label, 'success', ...args)
    },

    info(label: string, ...args: any[]) {
      return this.log(label, 'info', ...args)
    },

    error(label: string, ...args: any[]) {
      return this.log(label, 'error', ...args)
    },

    warn(label: string, ...args: any[]) {
      return this.log(label, 'warn', ...args)
    },

    log(
      label: string,
      type: 'info' | 'success' | 'error' | 'warn',
      ...data: unknown[]
    ) {
      const args = [
        makeLabel(name, label, type),
        ...data.map((item) => colorize(type, item, true)),
      ]
      switch (type) {
        case 'error': {
          if (!isMainThread) {
            parentPort?.postMessage({
              type: 'error',
              text: util.format(...args),
            })
            return
          }

          return console.error(...args)
        }
        default:
          if (silent) return

          if (!isMainThread) {
            parentPort?.postMessage({
              type: 'log',
              text: util.format(...args),
            })
            return
          }

          console.log(...args)
      }
    },
  }
}

import * as React from 'react';
import type { IMicroFeedbackComponent, IMicroFeedbackViewProps, VoteType } from './MicroFeedback.types';

export type IMicroFeedbackState = Pick<
  IMicroFeedbackViewProps,
  | 'vote'
  | 'isFollowUpVisible'
  | 'likeRef'
  | 'dislikeRef'
  | 'onCalloutDismiss'
  | 'onThanksDismiss'
  | 'onThanksShow'
  | 'onLikeVote'
  | 'onDislikeVote'
  | 'isThanksVisible'
>;

export const useMicroFeedbackState: IMicroFeedbackComponent['state'] = props => {
  const { sendFeedback } = props;
  const likeRef = React.useRef<HTMLDivElement | null>(null);
  const dislikeRef = React.useRef<HTMLDivElement | null>(null);
  const [timerHandle, setTimerHandle] = React.useState<number | undefined>(undefined);
  const [vote, setVote] = React.useState<VoteType>('no_vote');
  const [isFollowUpVisible, setIsFollowUpVisible] = React.useState(false);
  const [isThanksVisible, setIsThanksVisible] = React.useState(false);

  const onCalloutDismiss = React.useCallback((): void => {
    setIsFollowUpVisible(false);
  }, []);

  const onThanksDismiss = React.useCallback((): void => {
    clearTimeout(timerHandle);
    setIsThanksVisible(false);
  }, [timerHandle]);

  const processVote = React.useCallback(
    (newVote: VoteType): void => {
      // If the vote that is already selected is picked, then toggle off
      const updatedVote: VoteType = vote === newVote ? 'no_vote' : newVote;
      setIsFollowUpVisible(true);
      setVote(updatedVote);
      if (updatedVote !== 'no_vote' && sendFeedback) {
        sendFeedback(updatedVote);
      }
    },
    [sendFeedback, vote],
  );

  const onLikeVote = React.useCallback((): void => {
    processVote('like');
  }, [processVote]);

  const onDislikeVote = React.useCallback((): void => {
    processVote('dislike');
  }, [processVote]);

  const hideThanksMessage = React.useCallback((): void => {
    setIsThanksVisible(false);
  }, []);

  const onThanksShow = React.useCallback((): void => {
    setIsThanksVisible(true);

    // Hide the Thanks message after 2 seconds
    setTimerHandle(setTimeout(hideThanksMessage, 2000) as unknown as number);
  }, [hideThanksMessage]);

  const viewProps: IMicroFeedbackViewProps = {
    ...props,
    vote,
    isFollowUpVisible,
    likeRef,
    dislikeRef,
    onCalloutDismiss,
    onThanksDismiss,
    onThanksShow,
    onLikeVote,
    onDislikeVote,
    isThanksVisible,
  };
  return viewProps;
};

