import { fork, Serializable } from 'child_process';
import { join } from 'path';
import { PseudoIPCClient } from './pseudo-ipc';
import { signalToCode } from '../utils/exit-codes';

const pseudoIPCPath = process.argv[2];
const forkId = process.argv[3];

const script = join(__dirname, '../../bin/run-executor.js');

let execArgv: string[] | undefined;
if (process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV']) {
  execArgv = process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV'].split('|');
  delete process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV'];
}

const childProcess = fork(script, {
  stdio: ['inherit', 'inherit', 'inherit', 'ipc'],
  env: process.env,
  execArgv,
});

const pseudoIPC = new PseudoIPCClient(pseudoIPCPath);

pseudoIPC.onMessageFromParent(
  forkId,
  (message) => {
    childProcess.send(message);
  },
  () => {
    // IPC connection closed
    cleanup();
    process.exit(0);
  },
  () => {
    // IPC connection error
    cleanup();
    process.exit(0);
  }
);

pseudoIPC.notifyChildIsReady(forkId);

process.on('message', (message: Serializable) => {
  pseudoIPC.sendMessageToParent(message);
});

childProcess.on('exit', (code, signal) => {
  cleanup();
  if (code === null) code = signalToCode(signal);
  process.exit(code);
});

let isCleaningUp = false;
function cleanup() {
  if (isCleaningUp) {
    return;
  }
  isCleaningUp = true;

  // Kill child process if still running
  if (childProcess && !childProcess.killed) {
    childProcess.kill('SIGTERM');
  }

  // Close IPC connection
  try {
    pseudoIPC.close();
  } catch {
    // Ignore errors when closing, connection might already be broken
  }
}

// Terminate the child process when exiting
process.on('exit', () => {
  cleanup();
});
process.on('SIGINT', () => {
  cleanup();
  process.exit(signalToCode('SIGINT'));
});
process.on('SIGTERM', () => {
  cleanup();
});
process.on('SIGHUP', () => {
  cleanup();
});

import { centerStringInWidth } from './ui';

function getProgressBar(current: number, total: number, width = 40): string {
  const percentage = total > 0 ? current / total : 0;
  const filled = Math.round(width * percentage);
  const empty = width - filled;
  return '█'.repeat(filled) + '░'.repeat(empty);
}

function truncateStart(str: string, maxLen: number): string {
  if (str.length <= maxLen) return str;
  return '...' + str.slice(-(maxLen - 3));
}

export class ProgressDisplay {
  private current = 0;
  private total: number;
  private lastFile = '';
  private initialized: boolean = false;

  constructor(total: number) {
    this.total = total;
  }

  insertBefore(str: string) {
    process.stdout.write('\x1b[J');
    console.log(str);
  }

  row(maxWidth: number, minGap: number, ...parts: string[]): string {
    const totalPartsLength = parts.reduce((sum, part) => sum + part.length, 0);
    const calculatedGap = (maxWidth - totalPartsLength) / (parts.length - 1);
    if (calculatedGap < minGap) {
      const neededReduction = (minGap - calculatedGap) * (parts.length - 1);
      parts[0] = truncateStart(parts[0], parts[0].length - neededReduction);
    }
    return parts.join(' '.repeat(Math.max(calculatedGap, minGap)));
  }

  update(file: string, message?: string): void {
    this.current++;
    this.lastFile = file;

    // Move cursor up 3 lines and clear each line
    if (this.initialized) {
      process.stdout.write('\x1b[2F');
    } else {
      this.initialized = true;
    }

    if (message) {
      this.insertBefore(message);
    }
    this.renderCurrentStatus();
  }

  private renderCurrentStatus() {
    const termWidth = process.stdout.columns || 80;
    const adjustedTermWidth = termWidth - Math.floor(0.2 * termWidth);
    const progressBar = getProgressBar(
      this.current,
      this.total,
      adjustedTermWidth
    );

    // Line 1: Most recently copied file
    process.stdout.write(
      centerStringInWidth(
        this.row(
          adjustedTermWidth,
          4,
          this.lastFile,
          `[${this.current} / ${this.total}]`
        ),
        termWidth
      ) + '\x1b[K\n'
    );
    // Line 2: Progress bar
    process.stdout.write(
      centerStringInWidth(progressBar, termWidth) + '\x1b[K\n'
    );
  }

  finish(): void {
    // Add a newline after completion to separate from next output
    process.stdout.write('\n');
  }
}

import {readdir, readFile} from 'node:fs/promises'
import {dirname, join} from 'node:path'

import {memoizedWarn} from '../errors/warn'
import {TSConfig} from '../interfaces'
import {makeDebug} from '../logger'
import {mergeNestedObjects} from './util'

const debug = makeDebug('read-tsconfig')

function resolve(root: string, name: string): string | undefined {
  try {
    return require.resolve(name, {paths: [root]})
  } catch {
    // return undefined
  }
}

async function upUntil(path: string, test: (path: string) => Promise<boolean>): Promise<string | undefined> {
  let result: boolean | undefined
  try {
    result = await test(path)
  } catch {
    result = false
  }

  if (result) return path

  const parent = dirname(path)
  if (parent === path) return

  return upUntil(parent, test)
}

export async function readTSConfig(root: string, tsconfigName = 'tsconfig.json'): Promise<TSConfig | undefined> {
  const found: Record<string, any>[] = []

  let typescript: typeof import('typescript') | undefined
  try {
    typescript = require('typescript')
  } catch {
    try {
      typescript = require(root + '/node_modules/typescript')
    } catch {}
  }

  if (!typescript) {
    memoizedWarn(
      'Could not find typescript. Please ensure that typescript is a devDependency. Falling back to compiled source.',
    )
    return
  }

  const read = async (path: string): Promise<unknown> => {
    const localRoot = await upUntil(path, async (p) => (await readdir(p)).includes('package.json'))
    if (!localRoot) return

    try {
      const contents = await readFile(path, 'utf8')
      const parsed = typescript?.parseConfigFileTextToJson(path, contents).config

      found.push(parsed)

      if (parsed.extends) {
        if (parsed.extends.startsWith('.')) {
          const nextPath = resolve(localRoot, parsed.extends)
          return nextPath ? read(nextPath) : undefined
        }

        const resolved = resolve(localRoot, parsed.extends)
        if (resolved) return read(resolved)
      }

      return parsed
    } catch (error) {
      debug(error)
    }
  }

  await read(join(root, tsconfigName))

  return {
    compilerOptions: mergeNestedObjects(found, 'compilerOptions'),
    'ts-node': mergeNestedObjects(found, 'ts-node'),
  }
}

import { PnpmError } from '@pnpm/error'
import type { Finder, IncludedDependencies } from '@pnpm/types'

export type ReportAs = 'parseable' | 'json' | 'tree'

export function computeInclude (opts: { production?: boolean; dev?: boolean; optional?: boolean }): IncludedDependencies {
  return {
    dependencies: opts.production !== false,
    devDependencies: opts.dev !== false,
    optionalDependencies: opts.optional !== false,
  }
}

export function resolveFinders (opts: { findBy?: string[]; finders?: Record<string, Finder> }): Finder[] {
  const finders: Finder[] = []
  if (opts.findBy) {
    for (const finderName of opts.findBy) {
      if (opts.finders?.[finderName] == null) {
        throw new PnpmError('FINDER_NOT_FOUND', `No finder with name ${finderName} is found`)
      }
      finders.push(opts.finders[finderName])
    }
  }
  return finders
}

export function determineReportAs (opts: { parseable?: boolean; json?: boolean }): ReportAs {
  return opts.parseable ? 'parseable' : (opts.json ? 'json' : 'tree')
}

