export async function handler (
  opts: ListCommandOptions,
  params: string[]
): Promise<string> {
  if (params.length === 0 && opts.findBy == null) {
    throw new PnpmError('MISSING_PACKAGE_NAME', '`pnpm why` requires the package name or --find-by=<finder-name>')
  }

  const include = computeInclude(opts)
  const finders = resolveFinders(opts)
  const lockfileDir = opts.lockfileDir ?? opts.dir
  const reportAs = determineReportAs(opts)
  const depth = opts.cliOptions?.['depth'] as number | undefined

  const projectPaths = opts.recursive && opts.selectedProjectsGraph
    ? Object.keys(opts.selectedProjectsGraph)
    : [opts.dir]

  return whyForPackages(params, projectPaths, {
    depth,
    include,
    long: opts.long,
    lockfileDir,
    reportAs,
    modulesDir: opts.modulesDir,
    checkWantedLockfileOnly: opts.lockfileOnly,
    finders,
  })
}

import { Decimal, isObjectEnumValue, Sql } from '@prisma/client-runtime-utils'
import { assertNever } from '@prisma/internals'

import { isFieldRef } from '../core/model/FieldRef'
import { isSkip } from '../core/types'
import { isTypedSql, TypedSql, UnknownTypedSql } from '../core/types/exported'
import { JsArgs, JsInputValue } from '../core/types/exported/JsApi'
import { RawQueryArgs } from '../core/types/exported/RawQueryArgs'
import { isDate } from './date'
import { isDecimalJsLike } from './decimalJsLike'

export function deepCloneArgs(args: JsArgs | RawQueryArgs): JsArgs | RawQueryArgs {
  if (args instanceof Sql) {
    return cloneSql(args)
  }

  if (isTypedSql(args)) {
    return cloneTypedSql(args)
  }

  if (Array.isArray(args)) {
    const clone: RawQueryArgs = [args[0]]

    for (let i = 1; i < args.length; i++) {
      clone[i] = deepCloneValue(args[i] as JsInputValue)
    }

    return clone
  }
  const clone: JsArgs = {}
  for (const k in args) {
    clone[k] = deepCloneValue(args[k])
  }
  return clone
}

function cloneSql(rawParam: Sql): Sql {
  return new Sql(rawParam.strings, rawParam.values)
}

function cloneTypedSql(rawParam: UnknownTypedSql): UnknownTypedSql {
  return new TypedSql(rawParam.sql, rawParam.values)
}

// based on https://github.com/lukeed/klona/blob/v2.0.6/src/index.js
function deepCloneValue(x: JsInputValue): JsInputValue {
  if (typeof x !== 'object' || x == null || isObjectEnumValue(x) || isFieldRef(x) || isSkip(x)) {
    return x
  }

  if (isDecimalJsLike(x)) {
    return new Decimal(x.toFixed())
  }

  if (isDate(x)) {
    return new Date(+x)
  }

  if (ArrayBuffer.isView(x)) {
    return x.slice(0)
  }

  if (Array.isArray(x)) {
    let k = x.length
    let copy
    for (copy = Array(k); k--; ) {
      copy[k] = deepCloneValue(x[k])
    }
    return copy
  }

  if (typeof x === 'object') {
    const copy = {}
    for (const k in x) {
      if (k === '__proto__') {
        Object.defineProperty(copy, k, {
          value: deepCloneValue(x[k]),
          configurable: true,
          enumerable: true,
          writable: true,
        })
      } else {
        copy[k] = deepCloneValue(x[k])
      }
    }
    return copy
  }

  assertNever(x, 'Unknown value')
}

import { Decimal } from '@prisma/client-runtime-utils'
import type { QueryIntrospectionBuiltinType } from '@prisma/generator'

export type RawResponse = {
  columns: string[]
  types: QueryIntrospectionBuiltinType[]
  rows: unknown[][]
}

function deserializeValue(type: QueryIntrospectionBuiltinType, value: unknown): unknown {
  if (value === null) {
    return value
  }

  switch (type) {
    case 'bigint':
      return BigInt(value as string)

    case 'bytes': {
      const { buffer, byteOffset, byteLength } = Buffer.from(value as string, 'base64')
      return new Uint8Array(buffer, byteOffset, byteLength)
    }

    case 'decimal':
      return new Decimal(value as string)

    case 'datetime':
    case 'date':
      return new Date(value as string)

    case 'time':
      return new Date(`1970-01-01T${value}Z`)

    case 'bigint-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('bigint', v))
    case 'bytes-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('bytes', v))
    case 'decimal-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('decimal', v))
    case 'datetime-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('datetime', v))
    case 'date-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('date', v))
    case 'time-array':
      return (value as unknown[]).map((v: unknown) => deserializeValue('time', v))

    default:
      return value
  }
}

type DeserializedResponse = Array<Record<string, unknown>>

export function deserializeRawResult(response: RawResponse): DeserializedResponse {
  const deserializedResponse: DeserializedResponse = []
  // Performance optimization. See https://github.com/brianc/node-postgres/issues/3042
  const prebuiltEmptyObject = createPrebuiltEmptyResultObject(response)

  for (let i = 0; i < response.rows.length; i++) {
    const row = response.rows[i]
    const mappedRow = { ...prebuiltEmptyObject } as Record<string, unknown>

    for (let j = 0; j < row.length; j++) {
      mappedRow[response.columns[j]] = deserializeValue(response.types[j], row[j])
    }

    deserializedResponse.push(mappedRow)
  }

  return deserializedResponse
}

function createPrebuiltEmptyResultObject(response: RawResponse): Record<string, null> {
  const row = {}

  for (let i = 0; i < response.columns.length; i++) {
    row[response.columns[i]] = null
  }

  return row
}

import { execa } from 'execa';
import path from 'node:path';
import { readPackageUp } from 'read-pkg-up';

import { logger } from '../logger';
import { DebounceExecutor } from '../utils/debounce-executor';
import { getRoot } from '../utils/get-root';
import { listPackagesToBuild } from '../utils/list-packages';

export async function watch(options: { skipBuild?: boolean }) {
  logger.debug(`current working directory: ${process.cwd()}`);
  logger.debug(`CLI options: ${JSON.stringify(options)}`);

  logger.info('Building all packages...');
  try {
    if (!options.skipBuild) {
      await execa('pnpm', [`build:packages`]);
    }
  } catch (error) {
    logger.error('Failed to build all packages:', error);
  }

  logger.info('Watching all packages...');

  const packages = await listPackagesToBuild();

  const packageDirMap = Object.fromEntries(packages.map((pkg) => [path.normalize(pkg.dir), pkg]));

  const findAncestorPackage = (filePath: string): string | void => {
    for (let depth = 0; depth < 10; depth++) {
      const ancestor = path.normalize(path.resolve(filePath, '../'.repeat(depth)));

      const pkg = packageDirMap[ancestor];

      if (pkg) {
        return pkg.dir;
      }
    }
  };

  const chokidar = await import('chokidar');
  const watcher = chokidar.watch(getRoot(), {
    ignored: [
      '**/{.git,node_modules,dist,dist-types}/**',
      /temp/,
      /tmp/,
      /\.tsup/,
      '**/package.json',
    ],
    ignoreInitial: true,
    ignorePermissionErrors: true,
  });

  const executor = new DebounceExecutor(async (dir: string) => {
    const currentPackage = await readPackageUp({ cwd: dir });

    if (!currentPackage) {
      return;
    }

    const packageName = currentPackage.packageJson.name;
    logger.info(`Building ${packageName}`);

    await execa('turbo', ['build', `--filter=${packageName}`], {
      stdout: 'inherit',
      stderr: 'inherit',
    });
  });

  watcher.on('all', (event, filePath) => {
    logger.info(`Change detected: ${event} ${filePath}`);
    const pkgDir = findAncestorPackage(filePath);

    if (pkgDir) {
      logger.debug(`Going to rebuild package ${pkgDir}`);
      executor.push(pkgDir);
    } else {
      logger.debug("Nothing to do for this change, it's in a directory that we don't care about.");
    }
  });
}

import type { RouteManifest } from "./routes";

export type RoutesFormat = "json" | "jsx";

export function formatRoutes(
  routeManifest: RouteManifest,
  format: RoutesFormat,
) {
  switch (format) {
    case "json":
      return formatRoutesAsJson(routeManifest);
    case "jsx":
      return formatRoutesAsJsx(routeManifest);
  }
}

type JsonFormattedRoute = {
  id: string;
  index?: boolean;
  path?: string;
  caseSensitive?: boolean;
  file: string;
  children?: JsonFormattedRoute[];
};

export function formatRoutesAsJson(routeManifest: RouteManifest): string {
  function handleRoutesRecursive(
    parentId?: string,
  ): JsonFormattedRoute[] | undefined {
    let routes = Object.values(routeManifest).filter(
      (route) => route.parentId === parentId,
    );

    let children = [];

    for (let route of routes) {
      children.push({
        id: route.id,
        index: route.index,
        path: route.path,
        caseSensitive: route.caseSensitive,
        file: route.file,
        children: handleRoutesRecursive(route.id),
      });
    }

    if (children.length > 0) {
      return children;
    }
    return undefined;
  }

  return JSON.stringify(handleRoutesRecursive() || null, null, 2);
}

export function formatRoutesAsJsx(routeManifest: RouteManifest) {
  let output = "<Routes>";

  function handleRoutesRecursive(parentId?: string, level = 1): boolean {
    let routes = Object.values(routeManifest).filter(
      (route) => route.parentId === parentId,
    );

    let indent = Array(level * 2)
      .fill(" ")
      .join("");

    for (let route of routes) {
      output += "\n" + indent;
      output += `<Route${
        route.path ? ` path=${JSON.stringify(route.path)}` : ""
      }${route.index ? " index" : ""}${
        route.file ? ` file=${JSON.stringify(route.file)}` : ""
      }>`;
      if (handleRoutesRecursive(route.id, level + 1)) {
        output += "\n" + indent;
        output += "</Route>";
      } else {
        output = output.slice(0, -1) + " />";
      }
    }

    return routes.length > 0;
  }

  handleRoutesRecursive();

  output += "\n</Routes>";

  return output;
}

import type { PluginCache, SerializablePluginCache } from '../rollup/types';
import { error, logAnonymousPluginCache, logDuplicatePluginName } from './logs';
import { ANONYMOUS_OUTPUT_PLUGIN_PREFIX, ANONYMOUS_PLUGIN_PREFIX } from './pluginNames';

export function createPluginCache(cache: SerializablePluginCache): PluginCache {
	return {
		delete(id: string) {
			return delete cache[id];
		},
		get(id: string) {
			const item = cache[id];
			if (!item) return;
			item[0] = 0;
			return item[1];
		},
		has(id: string) {
			const item = cache[id];
			if (!item) return false;
			item[0] = 0;
			return true;
		},
		set(id: string, value: any) {
			cache[id] = [0, value];
		}
	};
}

export function getTrackedPluginCache(pluginCache: PluginCache, onUse: () => void): PluginCache {
	return {
		delete(id: string) {
			onUse();
			return pluginCache.delete(id);
		},
		get(id: string) {
			onUse();
			return pluginCache.get(id);
		},
		has(id: string) {
			onUse();
			return pluginCache.has(id);
		},
		set(id: string, value: any) {
			onUse();
			return pluginCache.set(id, value);
		}
	};
}

export const NO_CACHE: PluginCache = {
	delete() {
		return false;
	},
	get() {
		return undefined as any;
	},
	has() {
		return false;
	},
	set() {}
};

function uncacheablePluginError(pluginName: string): never {
	if (
		pluginName.startsWith(ANONYMOUS_PLUGIN_PREFIX) ||
		pluginName.startsWith(ANONYMOUS_OUTPUT_PLUGIN_PREFIX)
	) {
		return error(logAnonymousPluginCache());
	}
	return error(logDuplicatePluginName(pluginName));
}

export function getCacheForUncacheablePlugin(pluginName: string): PluginCache {
	return {
		delete() {
			return uncacheablePluginError(pluginName);
		},
		get() {
			return uncacheablePluginError(pluginName);
		},
		has() {
			return uncacheablePluginError(pluginName);
		},
		set() {
			return uncacheablePluginError(pluginName);
		}
	};
}

import { handleError } from '../../cli/logging';
import type {
	MaybeArray,
	MergedRollupOptions,
	RollupOptions,
	RollupWatcher
} from '../rollup/types';
import { ensureArray } from '../utils/ensureArray';
import { error, logInvalidOption } from '../utils/logs';
import { mergeOptions } from '../utils/options/mergeOptions';
import { URL_WATCH } from '../utils/urls';
import { loadFsEvents } from './fsevents-importer';
import { WatchEmitter } from './WatchEmitter';

export default function watch(configs: RollupOptions[] | RollupOptions): RollupWatcher {
	const emitter = new WatchEmitter() as RollupWatcher;

	watchInternal(configs, emitter).catch(error => {
		handleError(error);
	});

	return emitter;
}

function ensureTrailingSlash(path: string): string {
	if (path[path.length - 1] !== '/') {
		return `${path}/`;
	}
	return path;
}

function checkWatchConfig(config: MergedRollupOptions[]): void {
	for (const item of config) {
		if (typeof item.watch !== 'boolean' && item.watch?.allowInputInsideOutputPath) {
			break;
		}
		if (item.input && item.output) {
			const input = typeof item.input === 'string' ? ensureArray(item.input) : item.input;
			const outputs = ensureArray(item.output);
			for (const index in input) {
				const inputPath = input[index as keyof typeof input];
				if (typeof inputPath !== 'string') {
					continue;
				}
				const outputWithInputAsSubPath = outputs.find(
					({ dir }) => dir && ensureTrailingSlash(inputPath).startsWith(ensureTrailingSlash(dir))
				);
				if (outputWithInputAsSubPath) {
					error(
						logInvalidOption(
							'watch',
							URL_WATCH,
							`the input "${inputPath}" is a subpath of the output "${outputWithInputAsSubPath.dir}"`
						)
					);
				}
			}
		}
	}
}

async function watchInternal(configs: MaybeArray<RollupOptions>, emitter: RollupWatcher) {
	const optionsList = await Promise.all(
		ensureArray(configs).map(config => mergeOptions(config, true))
	);
	const watchOptionsList = optionsList.filter(config => config.watch !== false);
	if (watchOptionsList.length === 0) {
		return error(
			logInvalidOption(
				'watch',
				URL_WATCH,
				'there must be at least one config where "watch" is not set to "false"'
			)
		);
	}
	checkWatchConfig(watchOptionsList);
	await loadFsEvents();
	const { Watcher } = await import('./watch');
	new Watcher(watchOptionsList, emitter);
}

'use client'
import * as React from 'react'
import { shouldThrowError } from '@tanstack/query-core'
